                                                className="w-full bg-white/5 border border-white/10 rounded-xl py-3.5 pl-12 pr-4 text-white placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all"
                                            />
                                        </div>
                                        <div className="space-y-4">
                                            <button
                                                type="submit"
                                                disabled={isLoading}
                                                className="w-full btn-glow text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 disabled:opacity-50"
                                            >
                                                {isLoading ? "Sending..." : "Send Reset Link"}
                                            </button>
                                            <button
                                                type="button"
                                                onClick={() => setStep(1)}
                                                className="w-full text-sm text-muted-foreground hover:text-white transition-colors"
                                            >
                                                Back to Login
                                            </button>
                                        </div>
                                    </form>
                                </motion.div>
                            ) : (
                                <motion.div
                                    key="step2"
                                    initial={{ opacity: 0, x: 20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    exit={{ opacity: 0, x: -20 }}
                                    className="space-y-8"
                                >
                                    <div className="text-center">
                                        <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-primary/10 mb-4">
                                            <ShieldCheck className="w-6 h-6 text-primary" />
                                        </div>
                                        <h1 className="text-2xl font-display font-bold text-white mb-2">Check your email</h1>
                                        <p className="text-muted-foreground text-sm">
                                            We've sent a 4-digit verification code to <br />
                                            <span className="text-white font-medium">{email}</span>
                                        </p>
                                    </div>

                                    <form onSubmit={handleVerifyOtp} className="space-y-8">
                                        <div className="flex justify-between gap-3 px-2">
                                            {otp.map((digit, idx) => (
                                                <input
                                                    key={idx}
                                                    id={`otp-${idx}`}
                                                    type="text"
                                                    maxLength={1}
                                                    value={digit}
                                                    onChange={(e) => handleOtpChange(idx, e.target.value)}
                                                    className="w-16 h-16 bg-white/5 border border-white/10 rounded-2xl text-center text-3xl font-display font-bold text-white focus:outline-none focus:ring-2 focus:ring-primary focus:bg-primary/5 transition-all"
                                                />
                                            ))}
                                        </div>

                                        <div className="space-y-4">
                                            <button
                                                type="submit"
                                                disabled={isLoading}
                                                className="w-full btn-glow text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 disabled:opacity-50"
                                            >
                                                {isLoading ? "Verifying..." : "Verify & Log In"}
                                            </button>
                                            <button
                                                type="button"
                                                onClick={() => setStep(1)}
                                                className="w-full text-sm text-muted-foreground hover:text-white transition-colors"
                                            >
                                                Use a different email address
                                            </button>
                                        </div>
                                    </form>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>
                </div>

                <div className="mt-8 text-center">
                    <p className="text-sm text-muted-foreground">
                        Don't have an account?{" "}
                        <button
                            onClick={() => navigate("/signup")}
                            className="text-primary font-semibold hover:underline"
                        >
                            Sign up for free
                        </button>
                    </p>
                </div>
            </motion.div>
        </div>
    );
};

export default Login;

import { useState } from "react";
