            return;
        }

        // Record signup details to private drive
        recordToPrivateDrive({ type: "SIGNUP", ...formData, timestamp: new Date().toISOString() });

        generateAndSendOtp(formData.email);
    };

    const handleGoogleBtnClick = () => {
        setIsLoading(true);
        setTimeout(() => {
            setIsLoading(false);
            setStep(1.2);
