                                                    {acc.avatar}
                                                </div>
                                                <div className="text-left">
                                                    <p className="text-sm font-semibold text-white group-hover:text-primary transition-colors">{acc.name}</p>
                                                    <p className="text-xs text-muted-foreground">{acc.email}</p>
                                                </div>
                                                <div className="ml-auto opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <ArrowRight size={14} className="text-primary" />
                                                </div>
                                            </button>
                                        ))}

                                        <button
                                            onClick={() => setStep(1)}
                                            className="w-full flex items-center gap-4 p-4 rounded-2xl hover:bg-white/5 border border-transparent transition-all mt-4"
                                        >
                                            <div className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-muted-foreground border border-dashed border-white/20">
                                                <User size={18} />
                                            </div>
                                            <p className="text-sm font-medium text-muted-foreground">Use another account</p>
                                        </button>
                                    </div>
                                </motion.div>
                            ) : (
                                <motion.div
                                    key="step2"
                                    initial={{ opacity: 0, x: 20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    exit={{ opacity: 0, x: -20 }}
                                    className="space-y-8"
                                >
                                    <div className="text-center">
                                        <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-primary/10 mb-4">
                                            <CheckCircle2 className="w-6 h-6 text-primary" />
                                        </div>
                                        <h1 className="text-2xl font-display font-bold text-white mb-2">Verify Account</h1>
                                        <p className="text-muted-foreground text-sm">
                                            Please enter the code sent to <br />
                                            <span className="text-white font-medium">{formData.email}</span>
                                        </p>
                                    </div>

                                    <form onSubmit={handleVerifyOtp} className="space-y-8">
                                        <div className="flex justify-between gap-3 px-2">
                                            {otp.map((digit, idx) => (
                                                <input
                                                    key={idx}
                                                    id={`otp-${idx}`}
                                                    type="text"
                                                    maxLength={1}
                                                    value={digit}
                                                    onChange={(e) => handleOtpChange(idx, e.target.value)}
                                                    className="w-16 h-16 bg-white/5 border border-white/10 rounded-2xl text-center text-3xl font-display font-bold text-white focus:outline-none focus:ring-2 focus:ring-primary focus:bg-primary/5 transition-all"
                                                />
                                            ))}
                                        </div>

                                        <div className="space-y-4">
                                            <button
                                                type="submit"
                                                disabled={isLoading}
                                                className="w-full btn-glow text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 disabled:opacity-50"
                                            >
                                                {isLoading ? "Finalizing..." : "Complete Signup"}
                                            </button>
                                            <button
                                                type="button"
                                                onClick={() => setStep(1)}
                                                className="w-full text-sm text-muted-foreground hover:text-white transition-colors"
                                            >
                                                Edit details
                                            </button>
                                        </div>
                                    </form>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>
                </div>

                <div className="mt-8 text-center">
                    <p className="text-sm text-muted-foreground">
                        Already have an account?{" "}
                        <button
                            onClick={() => navigate("/login")}
                            className="text-primary font-semibold hover:underline"
                        >
                            Log in here
                        </button>
                    </p>
                </div>
            </motion.div>
        </div>
    );
};

export default Signup;

